package com.ichi2.anki

import android.net.Uri
import android.webkit.WebResourceResponse
import androidx.test.ext.junit.runners.AndroidJUnit4
import androidx.webkit.WebViewAssetLoader
import org.junit.Assert.assertEquals
import org.junit.Assert.assertNotNull
import org.junit.Assert.assertNull
import org.junit.Test
import org.junit.runner.RunWith
import java.io.File

@RunWith(AndroidJUnit4::class)
class ViewerAssetLoaderTest : RobolectricTest() {

    @Test
    fun `test CORS headers are set for media files`() {
        // Create a test SVG file
        val mediaDir = testContext.cacheDir
        val testFile = File(mediaDir, "test.svg")
        testFile.writeText("<svg></svg>")

        // Mock the media directory
        val loader = createTestAssetLoader(mediaDir)

        // Request the file
        val response = loader.shouldInterceptRequest(Uri.parse("http://127.0.0.1/test.svg"))

        assertNotNull("Response should not be null", response)

        // Check CORS headers
        val headers = response?.responseHeaders
        assertNotNull("Response headers should not be null", headers)
        assertEquals("Access-Control-Allow-Origin should be *", "*", headers?.get("Access-Control-Allow-Origin"))
        assertEquals("Access-Control-Allow-Methods should be GET, OPTIONS", "GET, OPTIONS", headers?.get("Access-Control-Allow-Methods"))
        assertEquals("Access-Control-Allow-Headers should be Content-Type", "Content-Type", headers?.get("Access-Control-Allow-Headers"))

        // Clean up
        testFile.delete()
    }

    @Test
    fun `test favicon request returns empty response`() {
        val mediaDir = testContext.cacheDir
        val loader = createTestAssetLoader(mediaDir)

        val response = loader.shouldInterceptRequest(Uri.parse("http://127.0.0.1/favicon.ico"))

        assertNotNull("Response should not be null for favicon", response)
        assertNull("MIME type should be null for favicon", response?.mimeType)
    }

    @Test
    fun `test non-existent file returns null`() {
        val mediaDir = testContext.cacheDir
        val loader = createTestAssetLoader(mediaDir)

        val response = loader.shouldInterceptRequest(Uri.parse("http://127.0.0.1/nonexistent.svg"))

        assertNull("Response should be null for non-existent file", response)
    }

    private fun createTestAssetLoader(mediaDir: File): WebViewAssetLoader {
        return WebViewAssetLoader.Builder()
            .setHttpAllowed(true)
            .setDomain("127.0.0.1")
            .addPathHandler("/") { path: String ->
                if (path == "favicon.ico") {
                    return@addPathHandler WebResourceResponse(null, null, java.io.ByteArrayInputStream(ByteArray(0)))
                }
                try {
                    val file = File(mediaDir, path)
                    val inputStream = java.io.FileInputStream(file)
                    val mimeType = com.ichi2.utils.AssetHelper.guessMimeType(path)
                    val responseHeaders = mapOf(
                        "Access-Control-Allow-Origin" to "*",
                        "Access-Control-Allow-Methods" to "GET, OPTIONS",
                        "Access-Control-Allow-Headers" to "Content-Type"
                    )
                    WebResourceResponse(mimeType, null, 200, "OK", responseHeaders, inputStream)
                } catch (e: Exception) {
                    null
                }
            }
            .build()
    }
}
"}

